10	import { useTranslation } from 'react-i18next';
11	import { Icons, ICON_SIZE } from '@bim-ai/ui';
12	import type { CollaborationConflictQueueV1 } from '../lib/collaborationConflictQueue';
13	
14	/**
15	 * StatusBar — spec §17.
16	 *
17	 * 28 px tall surface bar, bottom-of-shell. Shows clusters from left to
18	 * right: active level, current tool, snap mode group, grid toggle, model
19	 * coordinates, undo depth, ws connection, save state.
20	 *
21	 * - Coordinates use `aria-live="polite"` so screen-readers can announce
22	 *   changes without interrupting.
23	 * - The save-state pill uses `aria-live="polite"` too.
24	 * - Errors / red-alert states (offline, save failed) use
