115	function ConflictSlot({
116	  queue,
117	  onClear,
118	}: {
119	  queue: CollaborationConflictQueueV1;
120	  onClear?: () => void;
121	}): JSX.Element {
122	  const { t } = useTranslation();
123	  const [expanded, setExpanded] = useState(false);
124	  const retryLabels: Record<string, string> = {
125	    safe: t('statusbar.conflict.safeRetry'),
126	    blocked: t('statusbar.conflict.blocked'),
127	    requires_manual_edit: t('statusbar.conflict.manualEdit'),
128	  };
129	  const retryLabel = retryLabels[queue.retryAdvice] ?? queue.retryAdvice;
130	  return (
131	    <div className="relative flex items-center">
132	      <button
133	        type="button"
134	        aria-expanded={expanded}
135	        data-testid="conflict-pill"
136	        onClick={() => setExpanded((v) => !v)}
137	        className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 font-medium text-amber-700 hover:bg-amber-50 dark:text-amber-300 dark:hover:bg-amber-950/30"
138	        title={t('statusbar.conflict.pill')}
139	      >
140	        <Icons.advisorWarning size={ICON_SIZE.chrome} aria-hidden="true" />
141	        <span>{t('statusbar.conflict.label')}</span>
142	        <span className="rounded bg-amber-100 px-1 py-px text-[9px] dark:bg-amber-900/40">
143	          {retryLabel}
144	        </span>
145	      </button>
146	      {expanded ? (
147	        <div
148	          data-testid="collaboration-conflict-queue-readout"
149	          role="dialog"
150	          aria-label={t('statusbar.conflict.dialogAriaLabel')}
151	          className="absolute bottom-full right-0 z-50 mb-1 w-96 rounded border border-amber-500/40 bg-surface px-3 py-2 text-[10px] shadow-elev-2"
152	        >
153	          <div className="flex items-center justify-between">
154	            <span className="font-semibold text-amber-800 dark:text-amber-300">
155	              {t('statusbar.conflict.heading')}
156	            </span>
157	            <button
158	              type="button"
159	              aria-label={t('statusbar.conflict.dismissAriaLabel')}
160	              data-testid="conflict-dismiss"
161	              onClick={() => {
162	                setExpanded(false);
163	                onClear?.();
164	              }}
165	              className="rounded-sm px-1 py-0.5 text-muted hover:bg-surface-strong"
166	            >
167	              ✕
168	            </button>
169	          </div>
170	          <p className="mt-1 text-foreground">{queue.inspectionReadout}</p>
171	          {queue.inspectionReadoutSecondary ? (
172	            <p className="mt-0.5 text-muted">{queue.inspectionReadoutSecondary}</p>
173	          ) : null}
174	          {queue.mergePreflightReadout ? (
175	            <p className="mt-0.5 text-muted">{queue.mergePreflightReadout}</p>
176	          ) : null}
177	          <ul className="mt-1 list-disc space-y-0.5 ps-4 text-muted">
178	            <li>
179	              Retry advice: <code className="font-mono text-[9px]">{queue.retryAdvice}</code>
180	              {queue.reason ? (
181	                <>
182	                  {' · '}reason <code className="font-mono text-[9px]">{queue.reason}</code>
183	                </>
184	              ) : null}
185	            </li>
186	            {queue.rows.length > 0 ? (
187	              <li>
188	                {queue.rows.length} blocking row(s) · rules{' '}
189	                <code className="text-[9px]">{queue.rows.map((r) => r.ruleId).join(', ')}</code>
190	              </li>
191	            ) : null}
192	            {queue.firstBlockingCommandStep1Based !== null ? (
193	              <li>
194	                Blocking command step {queue.firstBlockingCommandStep1Based}
195	                {queue.blockingCommandType ? ` (${queue.blockingCommandType})` : ''}
196	              </li>
197	            ) : null}
198	          </ul>
199	        </div>
200	      ) : null}
201	    </div>
202	  );
203	}
204	
205	function LevelCluster({
206	  level,
207	  levels,
208	  onLevelChange,
209	}: {
210	  level: { id: string; label: string };
211	  levels: { id: string; label: string }[];
212	  onLevelChange?: (id: string) => void;
213	}): JSX.Element {
214	  const { t } = useTranslation();
215	  const [open, setOpen] = useState(false);
216	  const popoverId = useId();
217	  const close = useCallback(() => setOpen(false), []);
218	  const handleKey = useCallback(
219	    (event: KeyboardEvent<HTMLDivElement>) => {
220	      if (event.key === 'PageDown' || event.key === 'PageUp') {
221	        if (!levels.length) return;
222	        const idx = levels.findIndex((l) => l.id === level.id);
223	        if (idx < 0) return;
224	        const delta = event.key === 'PageDown' ? 1 : -1;
225	        const next = levels[(idx + delta + levels.length) % levels.length];
226	        event.preventDefault();
227	        onLevelChange?.(next.id);
228	      } else if (event.key === 'Escape') {
229	        close();
230	      }
231	    },
232	    [close, level.id, levels, onLevelChange],
233	  );
234	
235	  return (
236	    <div onKeyDown={handleKey} className="relative flex items-center gap-1">
237	      <button
238	        type="button"
239	        aria-expanded={open}
240	        aria-controls={popoverId}
241	        aria-haspopup="menu"
242	        onClick={() => setOpen((v) => !v)}
243	        title={t('statusbar.levelTitle')}
244	        className="rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
245	      >
246	        {t('statusbar.levelLabel')}{' '}
247	        <span className="font-medium text-foreground">{level.label}</span>
248	        <Icons.disclosureOpen size={ICON_SIZE.chrome} aria-hidden="true" className="ml-1 inline" />
249	      </button>
250	      {open ? (
251	        <div
252	          id={popoverId}
253	          role="menu"
254	          aria-label={t('statusbar.levels')}
255	          className="absolute bottom-full left-0 z-50 mb-1 w-48 rounded-md border border-border bg-surface text-sm shadow-elev-2"
256	        >
257	          {levels.map((l) => (
258	            <button
259	              key={l.id}
260	              type="button"
261	              role="menuitem"
262	              onClick={() => {
263	                onLevelChange?.(l.id);
264	                close();
265	              }}
266	              className={[
267	                'flex w-full items-center justify-between px-3 py-1.5 text-left',
268	                l.id === level.id ? 'bg-accent-soft text-foreground' : 'hover:bg-surface-strong',
269	              ].join(' ')}
270	            >
271	              {l.label}
272	              {l.id === level.id ? (
273	                <span className="text-xs text-muted">{t('statusbar.levelActive')}</span>
274	              ) : null}
275	            </button>
276	          ))}
277	        </div>
278	      ) : null}
279	    </div>
280	  );
281	}
282	
283	function ToolCluster({ toolLabel }: { toolLabel: string | null }): JSX.Element {
284	  const { t } = useTranslation();
285	  return (
286	    <div aria-live="polite" className="flex items-center gap-1" title={t('statusbar.toolTitle')}>
287	      {t('statusbar.toolLabel')}{' '}
288	      <span className="font-medium text-foreground">{toolLabel ?? '—'}</span>
289	    </div>
290	  );
291	}
292	
293	function SnapCluster({
294	  snapModes,
295	  onSnapToggle,
296	}: {
297	  snapModes: { id: string; label: string; on: boolean }[];
298	  onSnapToggle?: (id: string) => void;
299	}): JSX.Element {
300	  const { t } = useTranslation();
301	  return (
302	    <div className="flex items-center gap-1" title={t('statusbar.snapTitle')}>
303	      <Icons.snap size={ICON_SIZE.chrome} aria-hidden="true" className="text-muted" />
304	      <span>{t('statusbar.snapLabel')}</span>
305	      <div role="group" aria-label={t('statusbar.snapModes')} className="flex items-center gap-1">
306	        {snapModes.length === 0 ? (
307	          <span className="text-muted">{t('statusbar.snapOff')}</span>
308	        ) : (
309	          snapModes.map((s) => (
310	            <button
311	              key={s.id}
312	              type="button"
313	              role="switch"
314	              aria-checked={s.on}
315	              onClick={() => onSnapToggle?.(s.id)}
316	              data-active={s.on ? 'true' : 'false'}
317	              className={[
318	                'rounded-sm px-1.5 py-0.5',
319	                s.on ? 'bg-accent-soft text-foreground' : 'text-muted hover:bg-surface-strong',
320	              ].join(' ')}
321	            >
322	              {s.label}
323	            </button>
324	          ))
325	        )}
326	      </div>
327	    </div>
328	  );
329	}
330	
331	function GridCluster({
332	  gridOn,
333	  onGridToggle,
334	}: {
335	  gridOn: boolean;
336	  onGridToggle?: () => void;
337	}): JSX.Element {
338	  const { t } = useTranslation();
339	  return (
340	    <button
341	      type="button"
342	      role="switch"
343	      aria-checked={gridOn}
344	      onClick={onGridToggle}
345	      title={t('statusbar.gridTitle')}
346	      className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
347	    >
348	      <Icons.grid size={ICON_SIZE.chrome} aria-hidden="true" />
349	      {t('statusbar.gridLabel')}{' '}
350	      <span className="font-medium">{gridOn ? t('statusbar.gridOn') : t('statusbar.gridOff')}</span>
351	    </button>
352	  );
353	}
354	
355	function CoordCluster({
356	  cursorMm,
357	}: {
358	  cursorMm: { xMm: number; yMm: number } | null;
359	}): JSX.Element {
360	  const { t } = useTranslation();
361	  return (
362	    <div aria-live="polite" aria-label={t('statusbar.coordsLabel')} className="font-mono text-xs">
363	      {cursorMm
364	        ? `X ${(cursorMm.xMm / 1000).toFixed(2)} m   Y ${(cursorMm.yMm / 1000).toFixed(2)} m`
365	        : 'X —   Y —'}
366	    </div>
367	  );
368	}
369	
370	function UndoCluster({
371	  depth,
372	  onUndo,
373	  onRedo,
374	}: {
375	  depth: number;
376	  onUndo?: () => void;
377	  onRedo?: () => void;
378	}): JSX.Element {
379	  const { t } = useTranslation();
380	  return (
381	    <div className="flex items-center gap-1">
382	      <button
383	        type="button"
384	        onClick={onUndo}
385	        title={t('statusbar.undoTitle')}
386	        aria-label={t('statusbar.undoLabel')}
387	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
388	      >
389	        <Icons.undo size={ICON_SIZE.chrome} aria-hidden="true" />
390	      </button>
391	      <span className="text-muted">{depth}</span>
392	      <button
393	        type="button"
394	        onClick={onRedo}
395	        title={t('statusbar.redoTitle')}
396	        aria-label={t('statusbar.redoLabel')}
397	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
398	      >
399	        <Icons.redo size={ICON_SIZE.chrome} aria-hidden="true" />
400	      </button>
401	    </div>
402	  );
403	}
404	
405	function WsCluster({ state }: { state: StatusWsState }): JSX.Element {
406	  const { t } = useTranslation();
407	  const wsColors: Record<StatusWsState, string> = {
408	    connected: 'var(--color-success)',
409	    reconnecting: 'var(--color-warning)',
410	    offline: 'var(--color-danger)',
411	  };
412	  const color = wsColors[state];
413	  const label = t(`statusbar.ws.${state}`);
414	  return (
415	    <div
416	      aria-live={state === 'offline' ? 'assertive' : 'polite'}
417	      title={t('statusbar.connection', { label })}
418	      className="flex items-center gap-1"
419	    >
420	      <Icons.online size={ICON_SIZE.chrome} aria-hidden="true" style={{ color }} />
421	      <span>{t('statusbar.wsLabel')}</span>
422	      <span style={{ color }}>{label}</span>
423	    </div>
424	  );
425	}
426	
427	function SaveCluster({ state }: { state: StatusSaveState }): JSX.Element {
428	  const { t } = useTranslation();
429	  const label = t(`statusbar.save.${state}`);
430	  return (
431	    <div
432	      aria-live={state === 'error' ? 'assertive' : 'polite'}
433	      title={t('statusbar.save.title', { state: label })}
434	      className="font-medium"
435	      style={{
436	        color:
437	          state === 'error'
438	            ? 'var(--color-danger)'
439	            : state === 'unsynced'
440	              ? 'var(--color-warning)'
441	              : 'var(--color-foreground)',
442	      }}
443	    >
444	      {label}
445	    </div>
446	  );
447	}
448	
449	export type { ReactNode };
