2	import { type JSX, useMemo, useState } from 'react';
3	import type { Element } from '@bim-ai/core';
4	
5	import { applyCommand, ApiHttpError } from '../lib/api';
6	import { useBimStore } from '../state/store';
7	
8	/**
9	 * FED-01 — Manage Links dialog (full polish).
10	 *
11	 * Lists every `link_model` row in the host model with per-row controls for
12	 * delete, alignment mode, visibility mode, and revision pinning. Pinned links
13	 * surface a yellow drift badge when the source has advanced past the pinned
14	 * revision; clicking "Update" bumps the pinned revision to the current source
15	 * revision.
16	 */
17	
18	export interface ManageLinksDialogProps {
19	  open: boolean;
20	  onClose: () => void;
21	  /**
22	   * Optional override used by tests so they can pump commands through a fake
23	   * apply path. Production wiring uses the real `/api/.../commands` route.
24	   */
25	  applyCommandImpl?: typeof applyCommand;
26	}
27	
28	type LinkRow = Extract<Element, { kind: 'link_model' }>;
29	
30	type AlignMode = 'origin_to_origin' | 'project_origin' | 'shared_coords';
31	type VisibilityMode = 'host_view' | 'linked_view';
32	
33	const ALIGN_LABELS: Record<AlignMode, string> = {
34	  origin_to_origin: 'Origin → Origin',
35	  project_origin: 'Project Base Point',
36	  shared_coords: 'Shared Coords',
37	};
38	
39	const VIS_LABELS: Record<VisibilityMode, string> = {
40	  host_view: 'Host view',
41	  linked_view: 'Linked view',
42	};
43	
44	export function ManageLinksDialog({
45	  open,
46	  onClose,
47	  applyCommandImpl,
