406	        } else {
407	          setCollaborationConflictQueue(null);
408	        }
409	      }
410	    },
411	    [hydrateFromSnapshot, setActivity],
412	  );
413	
414	  /* ── Viewpoint field persistence (3D viewport internal controls) ────── */
415	  const persistViewpointField = useCallback(
416	    async (payload: { elementId: string; key: string; value: string }): Promise<void> => {
417	      const st = useBimStore.getState();
418	      if (!st.activeViewpointId || st.activeViewpointId !== payload.elementId) return;
419	      await onSemanticCommand({ type: 'updateElementProperty', ...payload });
420	    },
421	    [onSemanticCommand],
422	  );
423	
424	  // After the seed has hydrated, prune any restored tabs whose targets
425	  // no longer exist (e.g. a sheet deleted between sessions). If the
426	  // pruned set is empty, open a default Plan tab on the first level.
427	  // Runs once when the store transitions from empty → non-empty.
428	  const seededRef = useRef(false);
429	  useEffect(() => {
430	    if (seededRef.current) return;
431	    if (Object.keys(elementsById).length === 0) return;
432	    seededRef.current = true;
433	    setTabsState((s) => {
434	      const pruned = pruneTabsAgainstElements(s, elementsById);
435	      if (pruned.tabs.length > 0) return pruned;
436	      const levels = (Object.values(elementsById) as Element[]).filter(
437	        (e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level',
438	      );
439	      if (levels.length === 0) return pruned;
440	      const targetLevel =
441	        levels.find((l) => l.id === activeLevelId) ??
442	        levels.sort((a, b) => a.elevationMm - b.elevationMm)[0];
443	      if (!targetLevel) return pruned;
444	      return openTab(pruned, {
445	        kind: 'plan',
446	        targetId: targetLevel.id,
447	        label: `Plan · ${targetLevel.name}`,
448	      });
449	    });
450	  }, [elementsById, activeLevelId]);
451	
452	  /* ── Mode wiring (§7 + §20) ────────────────────────────────────────── */
453	  const handleModeChange = useCallback(
454	    (next: WorkspaceMode) => {
455	      setMode(next);
456	      if (next === 'plan' || next === 'plan-3d') setViewerMode('plan_canvas');
457	      else if (next === '3d') setViewerMode('orbit_3d');
458	      // Activate or open a tab of the matching kind so the canvas
459	      // mounts the right view.
460	      setTabsState((s) => {
461	        const fallback = defaultTabFallbackForKind(next, elementsById, activeLevelId);
462	        if (!fallback) return s;
463	        return activateOrOpenKind(s, next as TabKind, fallback);
464	      });
465	    },
466	    [setViewerMode, elementsById, activeLevelId],
467	  );
468	
469	  /* ── Global hotkeys: 1–7 modes, ?, V/W/D/M/S/etc tools ─────────────── */
470	  useEffect(() => {
471	    const onKey = (event: globalThis.KeyboardEvent): void => {
472	      const target = event.target as HTMLElement | null;
473	      if (target) {
474	        const tag = target.tagName;
475	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
476	        if (target.isContentEditable) return;
477	      }
478	      const fromMode = modeForHotkey(event.key);
479	      if (fromMode) {
480	        event.preventDefault();
481	        handleModeChange(fromMode);
482	        return;
483	      }
484	      if (event.key === '?') {
485	        event.preventDefault();
486	        setCheatsheetOpen((v) => !v);
487	        return;
488	      }
489	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
490	        event.preventDefault();
491	        setPaletteOpen((v) => !v);
492	        return;
493	      }
494	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
495	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
496	        event.preventDefault();
497	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
498	        return;
499	      }
500	      // Close active tab — Ctrl/⌘+W.
501	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
502	        event.preventDefault();
503	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
504	        return;
505	      }
506	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
507	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
508	        event.preventDefault();
509	        void handleUndoRedo(event.shiftKey ? false : true);
510	        return;
511	      }
512	      // V opens VV (Visibility/Graphics) dialog
513	      if (event.key === 'v' || event.key === 'V') {
514	        if (!event.metaKey && !event.ctrlKey && !event.altKey) {
515	          event.preventDefault();
516	          openVVDialog();
517	          return;
518	        }
519	      }
520	      // Ortho snap hold on Shift
521	      if (event.shiftKey) setOrthoSnapHold(true);
522	      // Tool hotkeys — match the spec'd letters from TOOL_REGISTRY.
523	      const upper = event.key.length === 1 ? event.key.toUpperCase() : event.key;
524	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
525	      const tool = (Object.values(toolRegistry) as { id: ToolId; hotkey: string }[]).find(
526	        (tool) => tool.hotkey === hotkeyLabel,
527	      );
528	      if (tool) {
529	        const legacy = toolIdToLegacy(tool.id);
530	        if (legacy) {
531	          event.preventDefault();
532	          setPlanTool(legacy);
533	        }
534	      }
535	    };
536	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
537	      if (!event.shiftKey) setOrthoSnapHold(false);
538	    };
539	    document.addEventListener('keydown', onKey);
540	    document.addEventListener('keyup', onKeyUp);
541	    return () => {
542	      document.removeEventListener('keydown', onKey);
543	      document.removeEventListener('keyup', onKeyUp);
544	    };
545	  }, [handleModeChange, handleUndoRedo, setPlanTool, setOrthoSnapHold, openVVDialog, toolRegistry]);
546	
547	  const browserSections = useMemo(() => buildBrowserSections(elementsById), [elementsById]);
548	
549	  const planProjectionPrimitives = useBimStore((s) => s.planProjectionPrimitives);
550	
551	  /* ── Debug: browser rendering budget (debounced, threshold warnings) ─ */
552	  useEffect(() => {
