554	    budgetTimerRef.current = setTimeout(() => {
555	      const readout = buildBrowserRenderingBudgetReadoutV1({
556	        elementsById,
557	        planProjectionPrimitives,
558	        scheduleHydratedRowCount: null,
559	        scheduleHydratedTab: null,
560	      });
561	      console.debug(
562	        '[bim] rendering budget:',
563	        formatBrowserRenderingBudgetLines(readout).join(' | '),
564	      );
565	      const bad = readout.rows.filter(
566	        (r) => r.progressiveState === 'deferred' || r.progressiveState === 'over_budget',
567	      );
568	      if (bad.length > 0) {
569	        console.warn(
