571	          readout.largeModelProofSummary,
572	          bad.map((r) => `${r.id}=${r.value ?? '?'}/${r.limit}`).join(', '),
573	        );
574	      }
575	    }, 2000);
576	    return () => {
577	      if (budgetTimerRef.current) clearTimeout(budgetTimerRef.current);
578	    };
579	  }, [elementsById, planProjectionPrimitives]);
580	
581	  /* ── Debug: selected element dump (dev only) ─────────────────────── */
